"""Template Jinja yang disematkan sebagai fallback untuk runtime serverless."""

EMBEDDED_TEMPLATES = {
    'admin/base.html': '<!doctype html>\n<html lang="id">\n<head>\n    <meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1">\n    <title>{% block title %}Admin Portfolio{% endblock %}</title>\n    <link href="https://fonts.googleapis.com/css2?family=DM+Sans:wght@400;500;600;700&family=Playfair+Display:wght@600;700&family=Material+Symbols+Outlined:opsz,wght,FILL,GRAD@20..48,100..700,0..1,0&display=swap" rel="stylesheet">\n    <link rel="stylesheet" href="/css/admin.css">\n</head>\n<body class="admin-page">\n<div class="admin-layout">\n    <aside class="sidebar">\n        <a class="sidebar-brand" href="{{ url_for(\'admin.dashboard\') }}">Portfolio</a>\n        <nav>\n            <a href="{{ url_for(\'admin.dashboard\') }}"><span class="material-symbols-outlined">dashboard</span>Dashboard</a>\n            <a href="{{ url_for(\'admin.profile\') }}"><span class="material-symbols-outlined">person</span>Profil</a>\n            <a href="{{ url_for(\'admin.skills\') }}"><span class="material-symbols-outlined">code</span>Skills</a>\n            <a href="{{ url_for(\'admin.experiences\') }}"><span class="material-symbols-outlined">timeline</span>Pengalaman</a>\n            <a href="{{ url_for(\'admin.projects\') }}"><span class="material-symbols-outlined">work</span>Proyek</a>\n            <a href="{{ url_for(\'admin.messages\') }}"><span class="material-symbols-outlined">mail</span>Pesan</a>\n        </nav>\n        <div class="sidebar-bottom">\n            <a href="{{ url_for(\'public.home\') }}" target="_blank"><span class="material-symbols-outlined">open_in_new</span>Lihat Website</a>\n            <form action="{{ url_for(\'auth.logout\') }}" method="post"><input type="hidden" name="csrf_token" value="{{ csrf_token() }}"><button type="submit"><span class="material-symbols-outlined">logout</span>Logout</button></form>\n        </div>\n    </aside>\n    <main class="admin-main">\n        <header class="admin-header"><div><small>Portfolio</small><h1>{% block heading %}Dashboard{% endblock %}</h1></div></header>\n        {% with messages = get_flashed_messages(with_categories=true) %}{% for category, message in messages %}<div class="admin-alert {{ category }}">{{ message }}</div>{% endfor %}{% endwith %}\n        {% block content %}{% endblock %}\n    </main>\n</div>\n<script src="/js/admin.js" defer></script>\n</body>\n</html>\n',
    'admin/dashboard.html': '{% extends "admin/base.html" %}\n{% block heading %}Dashboard{% endblock %}\n{% block content %}\n<div class="stat-grid">\n    <article><span class="material-symbols-outlined">code</span><strong>{{ counts.skills }}</strong><p>Kelompok skill</p></article>\n    <article><span class="material-symbols-outlined">timeline</span><strong>{{ counts.experiences }}</strong><p>Pengalaman</p></article>\n    <article><span class="material-symbols-outlined">work</span><strong>{{ counts.projects }}</strong><p>Proyek</p></article>\n    <article><span class="material-symbols-outlined">mark_email_unread</span><strong>{{ counts.unread }}</strong><p>Pesan belum dibaca</p></article>\n</div>\n<section class="admin-card">\n    <div class="card-title"><h2>Pesan terbaru</h2><a class="admin-btn secondary" href="{{ url_for(\'admin.messages\') }}">Lihat semua</a></div>\n    <div class="table-wrap"><table><thead><tr><th>Nama</th><th>Subjek</th><th>Tanggal</th><th>Status</th></tr></thead><tbody>\n    {% for item in recent_messages %}<tr><td><a href="{{ url_for(\'admin.message_detail\', item_id=item.id) }}">{{ item.name }}</a></td><td>{{ item.subject }}</td><td>{{ item.created_at.strftime(\'%d-%m-%Y %H:%M\') }}</td><td><span class="status {{ \'read\' if item.is_read else \'unread\' }}">{{ \'Dibaca\' if item.is_read else \'Baru\' }}</span></td></tr>{% else %}<tr><td colspan="4">Belum ada pesan.</td></tr>{% endfor %}\n    </tbody></table></div>\n</section>\n{% endblock %}\n',
    'admin/experience_form.html': '{% extends "admin/base.html" %}{% block heading %}{{ \'Edit\' if item.id else \'Tambah\' }} Pengalaman{% endblock %}{% block content %}\n<form class="admin-card admin-form" method="post"><input type="hidden" name="csrf_token" value="{{ csrf_token() }}"><div class="form-grid two">\n<label>Periode<input name="period" value="{{ item.period or \'\' }}" placeholder="2022 - Present" required></label><label>Tipe<select name="item_type"><option value="pengalaman" {% if item.item_type==\'pengalaman\' %}selected{% endif %}>pengalaman</option><option value="edukasi" {% if item.item_type==\'edukasi\' %}selected{% endif %}>Edukasi</option></select></label><label>Judul<input name="title" value="{{ item.title or \'\' }}" required></label><label>Organisasi<input name="organization" value="{{ item.organisasi or \'\' }}" required></label><label class="full">Deskripsi<textarea name="description" rows="6" required>{{ item.deskripsi or \'\' }}</textarea></label><label>Urutan<input type="nomor" name="sort_order" value="{{ item.sort_order or 0 }}"></label><label class="check-row"><input type="checkbox" name="is_active" {% if item.is_active %}checked{% endif %}> Tandai sebagai posisi aktif</label></div><button class="admin-btn primary">Simpan</button></form>{% endblock %}\n',
    'admin/experiences.html': '{% extends "admin/base.html" %}{% block heading %}Experience & Education{% endblock %}{% block content %}\n<div class="page-actions"><a class="admin-btn primary" href="{{ url_for(\'admin.experience_form\') }}">+ Tambah Data</a></div>\n<section class="admin-card"><div class="table-wrap"><table><thead><tr><th>Urutan</th><th>Periode</th><th>Judul</th><th>Organisasi</th><th>Tipe</th><th>Aksi</th></tr></thead><tbody>\n{% for item in experiences %}<tr><td>{{ item.sort_order }}</td><td>{{ item.period }}</td><td>{{ item.title }}</td><td>{{ item.organization }}</td><td>{{ item.item_type }}</td><td class="aksi"><a href="{{ url_for(\'admin.experience_form\', item_id=item.id) }}">Edit</a><form action="{{ url_for(\'admin.experience_delete\', item_id=item.id) }}" method="post" data-confirm="Hapus data ini?"><input type="hidden" name="csrf_token" value="{{ csrf_token() }}"><button>Hapus</button></form></td></tr>{% endfor %}\n</tbody></table></div></section>{% endblock %}\n',
    'admin/message_detail.html': '{% extends "admin/base.html" %}{% block heading %}Detail Pesan{% endblock %}{% block content %}\n<article class="admin-card message-card"><div class="card-title"><div><h2>{{ item.subject }}</h2><p>Dari {{ item.name }} · <a href="mailto:{{ item.email }}">{{ item.email }}</a></p></div><span>{{ item.created_at.strftime(\'%d-%m-%Y %H:%M\') }}</span></div><div class="message-body">{{ item.message }}</div><div class="page-actions"><a class="admin-btn primary" href="mailto:{{ item.email }}?subject=Re: {{ item.subject|urlencode }}">Balas lewat email</a><a class="admin-btn secondary" href="{{ url_for(\'admin.messages\') }}">Kembali</a></div></article>{% endblock %}\n',
    'admin/messages.html': '{% extends "admin/base.html" %}{% block heading %}Pesan Masuk{% endblock %}{% block content %}\n<section class="admin-card"><div class="table-wrap"><table><thead><tr><th>Nama</th><th>Email</th><th>Subjek</th><th>Tanggal</th><th>Status</th><th>Aksi</th></tr></thead><tbody>\n{% for item in messages %}<tr><td>{{ item.name }}</td><td>{{ item.email }}</td><td><a href="{{ url_for(\'admin.message_detail\', item_id=item.id) }}">{{ item.subject }}</a></td><td>{{ item.created_at.strftime(\'%d-%m-%Y %H:%M\') }}</td><td><span class="status {{ \'read\' if item.is_read else \'unread\' }}">{{ \'Dibaca\' if item.is_read else \'Baru\' }}</span></td><td class="actions"><a href="{{ url_for(\'admin.message_detail\', item_id=item.id) }}">Buka</a><form action="{{ url_for(\'admin.message_delete\', item_id=item.id) }}" method="post" data-confirm="Hapus pesan ini?"><input type="hidden" name="csrf_token" value="{{ csrf_token() }}"><button>Hapus</button></form></td></tr>{% else %}<tr><td colspan="6">Belum ada pesan.</td></tr>{% endfor %}</tbody></table></div></section>{% endblock %}\n',
    'admin/profile.html': '{% extends "admin/base.html" %}\n{% block heading %}Profil Utama{% endblock %}\n{% block content %}\n<form class="admin-card admin-form" method="post" enctype="multipart/form-data">\n    <input type="hidden" name="csrf_token" value="{{ csrf_token() }}">\n    <div class="form-grid two">\n        <label>Nama brand<input name="brand_name" value="{{ profile.brand_name or \'\' }}" required></label>\n        <label>Nama lengkap<input name="full_name" value="{{ profile.full_name or \'\' }}" required></label>\n        <label class="full">Headline<input name="headline" value="{{ profile.headline or \'\' }}" required></label>\n        <label class="full">Deskripsi singkat<textarea name="short_intro" rows="3" required>{{ profile.short_intro or \'\' }}</textarea></label>\n        <label>Teks ketersediaan<input name="availability_text" value="{{ profile.availability_text or \'\' }}"></label>\n        <label>Pengalaman<input name="years_experience" value="{{ profile.years_experience or \'\' }}"></label>\n        <label class="full">Tentang saya paragraf 1<textarea name="about_text" rows="5" required>{{ profile.about_text or \'\' }}</textarea></label>\n        <label class="full">Tentang saya paragraf 2<textarea name="about_text_secondary" rows="4" required>{{ profile.about_text_secondary or \'\' }}</textarea></label>\n        <label>Email<input type="email" name="email" value="{{ profile.email or \'\' }}" required></label>\n        <label>Telepon<input name="phone" value="{{ profile.phone or \'\' }}" required></label>\n        <label>Lokasi<input name="location" value="{{ profile.location or \'\' }}" required></label>\n        <label>Pendidikan<input name="education" value="{{ profile.education or \'\' }}" required></label>\n        <label>Status kerja<input name="work_status" value="{{ profile.work_status or \'\' }}"></label>\n        <label>Teks footer<input name="footer_text" value="{{ profile.footer_text or \'\' }}"></label>\n        <label>URL GitHub<input type="url" name="github_url" value="{{ profile.github_url or \'\' }}"></label>\n        <label>URL LinkedIn<input type="url" name="linkedin_url" value="{{ profile.linkedin_url or \'\' }}"></label>\n        <label>Foto hero<input type="file" name="hero_image" accept="image/*"><small>Gambar saat ini: {{ profile.hero_image_url or \'-\' }}</small></label>\n        <label>Foto about<input type="file" name="about_image" accept="image/*"><small>Gambar saat ini: {{ profile.about_image_url or \'-\' }}</small></label>\n        <label class="full">File CV PDF<input type="file" name="cv_file" accept="application/pdf"><small>CV saat ini: {{ profile.cv_url or \'-\' }}</small></label>\n    </div>\n    <button class="admin-btn primary" type="submit">Simpan Profil</button>\n</form>\n{% endblock %}\n',
    'admin/project_form.html': '{% extends "admin/base.html" %}\n\n{% block heading %}\n    {{ "Edit" if item.id else "Tambah" }} Proyek\n{% endblock %}\n\n{% block content %}\n<form\n    class="admin-card admin-form"\n    method="post"\n    enctype="multipart/form-data"\n>\n    <input\n        type="hidden"\n        name="csrf_token"\n        value="{{ csrf_token() }}"\n    >\n\n    <div class="form-grid two">\n        <label>\n            Judul\n            <input\n                type="text"\n                name="title"\n                value="{{ request.form.get(\'title\', item.title or \'\') }}"\n                required\n            >\n        </label>\n\n        <label>\n            Urutan\n            <input\n                type="number"\n                name="sort_order"\n                value="{{ request.form.get(\n                    \'sort_order\',\n                    item.sort_order or 0\n                ) }}"\n            >\n        </label>\n\n        <label class="full">\n            Deskripsi\n            <textarea\n                name="description"\n                rows="5"\n                required\n            >{{ request.form.get(\n                \'description\',\n                item.description or \'\'\n            ) }}</textarea>\n        </label>\n\n        <label class="full">\n            Teknologi\n            <textarea\n                name="technologies"\n                rows="3"\n                required\n            >{{ request.form.get(\n                \'technologies\',\n                item.technologies or \'\'\n            ) }}</textarea>\n\n            <small>Pisahkan dengan baris baru atau koma.</small>\n        </label>\n\n        <label>\n            Live URL\n            <input\n                type="url"\n                name="live_url"\n                value="{{ request.form.get(\n                    \'live_url\',\n                    item.live_url or \'\'\n                ) }}"\n            >\n        </label>\n\n        <label>\n            Code URL\n            <input\n                type="url"\n                name="code_url"\n                value="{{ request.form.get(\n                    \'code_url\',\n                    item.code_url or \'\'\n                ) }}"\n            >\n        </label>\n\n        <label class="full">\n            Gambar proyek\n            <input\n                type="file"\n                name="image"\n                accept="image/jpeg,image/png,image/webp"\n            >\n\n            <small>\n                Gambar saat ini: {{ item.image_url or "-" }}\n            </small>\n        </label>\n\n        <label class="check-row">\n            <input\n                type="checkbox"\n                name="is_featured"\n                {% if item.is_featured or not item.id %}checked{% endif %}\n            >\n            Tampilkan di halaman utama\n        </label>\n    </div>\n\n    <button\n        type="submit"\n        class="admin-btn primary"\n    >\n        Simpan\n    </button>\n</form>\n{% endblock %}',
    'admin/projects.html': '{% extends "admin/base.html" %}{% block heading %}Projects{% endblock %}{% block content %}\n<div class="page-actions"><a class="admin-btn primary" href="{{ url_for(\'admin.project_form\') }}">+ Tambah Proyek</a></div>\n<section class="admin-card"><div class="table-wrap"><table><thead><tr><th>Urutan</th><th>Judul</th><th>Teknologi</th><th>Featured</th><th>Aksi</th></tr></thead><tbody>\n{% for item in projects %}<tr><td>{{ item.sort_order }}</td><td>{{ item.title }}</td><td>{{ item.tech_list|join(\', \') }}</td><td>{{ \'Ya\' if item.is_featured else \'Tidak\' }}</td><td class="actions"><a href="{{ url_for(\'admin.project_form\', item_id=item.id) }}">Edit</a><form action="{{ url_for(\'admin.project_delete\', item_id=item.id) }}" method="post" data-confirm="Hapus proyek ini?"><input type="hidden" name="csrf_token" value="{{ csrf_token() }}"><button>Hapus</button></form></td></tr>{% endfor %}</tbody></table></div></section>{% endblock %}\n',
    'admin/skill_form.html': '{% extends "admin/base.html" %}{% block heading %}{{ \'Edit\' if item.id else \'Tambah\' }} Skill{% endblock %}{% block content %}\n<form class="admin-card admin-form" method="post"><input type="hidden" name="csrf_token" value="{{ csrf_token() }}">\n<div class="form-grid two"><label>Kategori<input name="category" value="{{ item.category or \'\' }}" required></label><label>Ikon Material Symbols<input name="icon" value="{{ item.icon or \'code\' }}" required><small>Contoh: code, database, brush, construction</small></label><label class="full">Daftar kemampuan<textarea name="items" rows="7" required>{{ item.items or \'\' }}</textarea><small>Satu kemampuan per baris.</small></label><label>Urutan<input type="number" name="sort_order" value="{{ item.sort_order or 0 }}"></label></div><button class="admin-btn primary">Simpan</button></form>{% endblock %}\n',
    'admin/skills.html': '{% extends "admin/base.html" %}{% block heading %}Skills{% endblock %}{% block content %}\n<div class="page-actions"><a class="admin-btn primary" href="{{ url_for(\'admin.skill_form\') }}">+ Tambah Skill</a></div>\n<section class="admin-card"><div class="table-wrap"><table><thead><tr><th>Urutan</th><th>Ikon</th><th>Kategori</th><th>Daftar</th><th>Aksi</th></tr></thead><tbody>\n{% for item in skills %}<tr><td>{{ item.sort_order }}</td><td><span class="material-symbols-outlined">{{ item.icon }}</span></td><td>{{ item.category }}</td><td>{{ item.item_list|join(\', \') }}</td><td class="actions"><a href="{{ url_for(\'admin.skill_form\', item_id=item.id) }}">Edit</a><form action="{{ url_for(\'admin.skill_delete\', item_id=item.id) }}" method="post" data-confirm="Hapus skill ini?"><input type="hidden" name="csrf_token" value="{{ csrf_token() }}"><button>Hapus</button></form></td></tr>{% else %}<tr><td colspan="5">Belum ada skill.</td></tr>{% endfor %}\n</tbody></table></div></section>{% endblock %}\n',
    'auth/login.html': '<!doctype html>\n<html lang="id">\n<head>\n    <meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1">\n    <title>Login Admin | Portfolio</title>\n    <link href="https://fonts.googleapis.com/css2?family=DM+Sans:wght@400;500;600;700&family=Playfair+Display:wght@600;700&display=swap" rel="stylesheet">\n    <link rel="stylesheet" href="/css/admin.css">\n</head>\n<body class="auth-page">\n    <main class="login-card">\n        <a class="login-brand" href="{{ url_for(\'public.home\') }}">Portofolio</a>\n        <h1>Login Admin</h1>\n        <p>Masuk untuk mengelola profil, skill, pengalaman, proyek, dan pesan.</p>\n        {% with messages = get_flashed_messages(with_categories=true) %}{% for category, message in messages %}<div class="admin-alert {{ category }}">{{ message }}</div>{% endfor %}{% endwith %}\n        <form method="post">\n            <input type="hidden" name="csrf_token" value="{{ csrf_token() }}">\n            <label>Email<input type="email" name="email" value="{{ email or \'\' }}" autocomplete="email" required></label>\n            <label>Password<input type="password" name="password" autocomplete="current-password" required></label>\n            <label class="check-row"><input type="checkbox" name="remember"> Ingat saya</label>\n            <button type="submit">Login</button>\n        </form>\n        <a class="back-link" href="{{ url_for(\'public.home\') }}">← Kembali ke portofolio</a>\n    </main>\n</body>\n</html>\n',
    'base.html': '<!doctype html>\n<html lang="id">\n<head>\n    <meta charset="utf-8">\n    <meta name="viewport" content="width=device-width, initial-scale=1">\n    <meta name="description" content="Website portofolio profesional">\n    <title>{% block title %}Portfolio{% endblock %}</title>\n    <link rel="preconnect" href="https://fonts.googleapis.com">\n    <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>\n    <link href="https://fonts.googleapis.com/css2?family=DM+Sans:wght@400;500;600;700&family=Inter:wght@500;600&family=Playfair+Display:wght@600;700&family=Material+Symbols+Outlined:opsz,wght,FILL,GRAD@20..48,100..700,0..1,0&display=swap" rel="stylesheet">\n    <link rel="stylesheet" href="/css/main.css">\n    <link rel="stylesheet" href="/css/responsive.css">\n    {% block head %}{% endblock %}\n</head>\n<body>\n    {% with messages = get_flashed_messages(with_categories=true) %}\n        {% if messages %}\n            <div class="flash-stack" aria-live="polite">\n                {% for category, message in messages %}\n                    <div class="flash flash-{{ category }}">{{ message }}</div>\n                {% endfor %}\n            </div>\n        {% endif %}\n    {% endwith %}\n    {% block content %}{% endblock %}\n    <script src="/js/main.js" defer></script>\n    {% block scripts %}{% endblock %}\n</body>\n</html>\n',
    'public/home.html': '{% extends "base.html" %}\n{% block title %}{{ profile.brand_name if profile else \'Portofolio\' }} | Portfolio{% endblock %}\n{% block content %}\n{% set hero_fallback = \'/images/default-hero.jpg\' %}\n{% set about_fallback = \'/images/default-about.jpg\' %}\n<nav class="site-nav" aria-label="Navigasi utama">\n    <div class="container nav-inner">\n        <a class="brand" href="#home">{{ profile.brand_name if profile else \'Portofolio\' }}</a>\n        <div class="desktop-nav">\n            <a class="nav-link active" href="#home">Home</a>\n            <a class="nav-link" href="#about">Tentang</a>\n            <a class="nav-link" href="#skills">Skills</a>\n            <a class="nav-link" href="#experience">Pengalaman</a>\n            <a class="nav-link" href="#projects">Proyek</a>\n            <a class="nav-link" href="#contact">Kontak</a>\n        </div>\n        <button class="menu-toggle" type="button" aria-controls="mobile-menu" aria-expanded="false">\n            <span class="material-symbols-outlined">menu</span>\n        </button>\n    </div>\n    <div id="mobile-menu" class="mobile-nav" hidden>\n        <a href="#home">Home</a><a href="#about">About</a><a href="#skills">Skills</a>\n        <a href="#experience">Experience</a><a href="#projects">Projects</a><a href="#contact">Contact</a>\n    </div>\n</nav>\n\n<main>\n    <section class="hero container section-anchor" id="home">\n        <div class="hero-grid">\n            <div class="hero-copy reveal">\n                <div class="eyebrow">{{ profile.availability_text if profile else \'Hallo Saya!\' }}</div>\n                <h1> <span>{{ profile.full_name if profile else \'Nama Lengkap\' }}</span> Nelvin Jovan Malmsteen Duha</h1>\n                <p class="hero-headline">{{ profile.headline if profile else \'Web Developer & UI/UX Enthusiast\' }}</p>\n                <div class="hero-actions">\n                    <a class="btn btn-primary" href="#projects">Lihat Proyek</a>\n                    {% if profile and profile.cv_url %}<a class="btn btn-outline" href="{{ profile.cv_url }}" target="_blank" rel="noopener">Kirim Pesan</a>{% else %}<a class="btn btn-outline" href="#contact">Kirim Pesan</a>{% endif %}\n                </div>\n                \n            </div>\n            <div class="hero-media reveal">\n                <div class="hero-glow"></div>\n                <div class="hero-image-frame">\n                    <img src="{{ profile.hero_image_url if profile and profile.hero_image_url else hero_fallback }}" alt="Foto profesional {{ profile.full_name if profile else \'pemilik portofolio\' }}">\n                </div>\n            </div>\n        </div>\n    </section>\n\n    <section class="about-section section-anchor" id="about">\n        <div class="container about-grid">\n            <div class="about-media reveal">\n                <div class="about-image-frame"><img src="{{ profile.about_image_url if profile and profile.about_image_url else about_fallback }}" alt="Ruang kerja profesional"></div>\n            </div>\n            <div class="about-copy reveal">\n                <div class="section-heading align-left"><h2>Tentang Saya</h2><span class="heading-line"></span></div>\n                <p class="lead">{{ profile.about_text if profile else \'\' }}</p>\n            </div>\n        </div>\n    </section>\n\n    <section class="skills-section container section-anchor" id="skills">\n        <div class="section-heading reveal"><h2>Kemampuan Saya</h2><p></p></div>\n        <div class="skill-grid">\n            {% for skill in skills %}\n            <article class="skill-card reveal">\n                <span class="material-symbols-outlined skill-icon">{{ skill.icon }}</span>\n                <h3>{{ skill.category }}</h3>\n                <ul>{% for item in skill.item_list %}<li>{{ item }}</li>{% endfor %}</ul>\n            </article>\n            {% endfor %}\n        </div>\n    </section>\n\n    <section class="experience-section section-anchor" id="experience">\n        <div class="container experience-grid">\n            <div class="experience-intro reveal"><h2>Experience &<br>Education</h2><p></p></div>\n            <div class="timeline">\n                {% for item in experiences %}\n                <article class="timeline-item reveal">\n                    <div class="timeline-marker {% if item.is_active %}active{% endif %}"></div>\n                    <div class="timeline-content">\n                        <span class="timeline-period">{{ item.period }}</span>\n                        <h3>{{ item.title }}</h3>\n                        <strong>{{ item.organization }}</strong>\n                        <p>{{ item.description }}</p>\n                    </div>\n                </article>\n                {% endfor %}\n            </div>\n        </div>\n    </section>\n\n    <section class="projects-section container section-anchor" id="projects">\n        <div class="project-heading reveal">\n            <div><h2>Featured Projects</h2><p></p></div>\n\n        </div>\n        <div class="project-grid">\n            {% for project in projects %}\n            <article class="project-card reveal">\n                <div class="project-image"><img src="{{ project.image_url or \'/images/project-placeholder.svg\' }}" alt="Tampilan proyek {{ project.title }}"></div>\n                <div class="project-body">\n                    <div class="project-tags">{% for tech in project.tech_list %}<span>{{ tech }}</span>{% endfor %}</div>\n                    <h3>{{ project.title }}</h3>\n                    <p>{{ project.description }}</p>\n                    <div class="project-links">\n                        {% if project.live_url %}<a href="{{ project.live_url }}" target="_blank" rel="noopener"><span class="material-symbols-outlined">visibility</span>Live Demo</a>{% endif %}\n                        {% if project.code_url %}<a href="{{ project.code_url }}" target="_blank" rel="noopener"><span class="material-symbols-outlined">terminal</span>Code</a>{% endif %}\n                    </div>\n                </div>\n            </article>\n            {% endfor %}\n        </div>\n    </section>\n\n    <section class="contact-section container section-anchor" id="contact">\n        <div class="contact-card reveal">\n            <div class="contact-info">\n                <div><h2>Mari Kerja Sama</h2><p></p></div>\n                <div class="contact-list">\n                    <div><span class="material-symbols-outlined">mail</span><p><small>Email Me</small><strong>{{ profile.email if profile else \'\' }}</strong></p></div>\n                    <div><span class="material-symbols-outlined">call</span><p><small>Call Me</small><strong>{{ profile.phone if profile else \'\' }}</strong></p></div>\n                    <div><span class="material-symbols-outlined">location_on</span><p><small>Location</small><strong>{{ profile.location if profile else \'\' }}</strong></p></div>\n                </div>\n            </div>\n            <div class="contact-form-wrap">\n                <form\n  class="contact-form"\n  method="POST"\n  action="{{ url_for(\'public.contact\') }}"\n>\n  <input\n    type="hidden"\n    name="csrf_token"\n    value="{{ csrf_token() }}"\n  >\n\n  <div class="form-row">\n    <label>\n      Nama\n      <input\n        type="text"\n        name="name"\n        placeholder="Masukkan Nama Kamu"\n        maxlength="150"\n        autocomplete="name"\n        required\n      >\n    </label>\n\n    <label>\n      Email\n      <input\n        type="email"\n        name="email"\n        placeholder="Masukkan Email Kamu"\n        maxlength="190"\n        autocomplete="email"\n        required\n      >\n    </label>\n  </div>\n\n  <label>\n    Subject\n    <input\n      type="text"\n      name="subject"\n      placeholder="Judul Pesan"\n      maxlength="220"\n      required\n    >\n  </label>\n\n  <label>\n    Pesan\n    <textarea\n      name="message"\n      rows="6"\n      placeholder="Tulis Pesan Kamu"\n      maxlength="5000"\n      required\n    ></textarea>\n  </label>\n\n  <button\n    type="submit"\n    class="btn btn-primary submit-btn"\n  >\n    Kirim Pesan\n  </button>\n</form>\n            </div>\n        </div>\n    </section>\n</main>\n\n<footer class="site-footer">\n    <div class="container footer-grid">\n        <div><a class="brand" href="#home">{{ profile.brand_name if profile else \'Portofolio\' }}</a><p>© {{ 2026 }} {{ profile.footer_text if profile else \'\' }}. All rights reserved.</p></div>\n        <div class="footer-links"><a href="#home">Home</a><a href="#about">About</a><a href="#projects">Projects</a><a href="{{ url_for(\'auth.login\') }}">Admin</a></div>\n        <div class="footer-social">\n            {% if profile and profile.linkedin_url %}<a href="{{ profile.linkedin_url }}" target="_blank" rel="noopener"><span class="material-symbols-outlined">share</span></a>{% endif %}\n            {% if profile and profile.github_url %}<a href="{{ profile.github_url }}" target="_blank" rel="noopener"><span class="material-symbols-outlined">terminal</span></a>{% endif %}\n            <a class="back-to-top" href="#home"><span class="material-symbols-outlined">arrow_upward</span></a>\n        </div>\n    </div>\n</footer>\n{% endblock %}\n',
}
